document.addEventListener('DOMContentLoaded',()=>{console.log('ToolNest Utilities Loaded');const e=document.getElementById('mobileMenuToggle');e&&e.addEventListener('click',()=>{document.querySelector('.nav-links').classList.toggle('active')})});async function copyToClipboard(e,t){try{await navigator.clipboard.writeText(e);const o=t.innerText;t.innerText='Copied!',t.classList.add('success-state'),setTimeout(()=>{t.innerText=o,t.classList.remove('success-state')},2e3)}catch(e){console.error('Failed to copy text: ',e),showNotification('Failed to copy to clipboard.','error')}}function showNotification(e,t='success'){const o=document.createElement('div');o.className=`toast toast-${t}`,o.textContent=e,document.body.appendChild(o),setTimeout(()=>o.remove(),3e3)}function initAdSense(e){setTimeout(()=>{const t=document.createElement('script');t.src=`https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=${e}`,t.async=!0,t.crossOrigin='anonymous',document.head.appendChild(t)},3e3)}function validateEmail(e){return/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e)}function validateContactForm(){const e=document.getElementById('email'),t=document.getElementById('message');return e&&!validateEmail(e.value)?(showNotification('Please enter a valid email','error'),!1):!t||t.value.length<10?(showNotification('Message must be at least 10 characters','error'),!1):(showNotification('Thank you! Your message has been sent.','success'),!0)}
